#nullable enable // autogenerated

using System;

namespace MVZ2.Metas
{
    public abstract class AlmanacVariableOperationUnary : AlmanacVariableOperation
    {

        public AlmanacVariableReference reference;

        public AlmanacVariableOperationUnary(AlmanacVariableReference reference)
        {
            this.reference = reference;
        }

        public double GetOperand(AlmanacVariableContext context)
        {
            var value = reference.GetVariableValue(context);
            if (Convert.ToDouble(value) is double doubleValue)
                return doubleValue;
            return 1;
        }
    }
}
